package com.facilcomanda.tableservice.entity; import com.facilcomanda.common.enums.TableState; import jakarta.persistence.*; @Entity @Table(name="restaurant_tables", indexes=@Index(name="idx_table_org", columnList="organization_id")) public class RestaurantTable { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; private Long organizationId; private String name; private String description; @Enumerated(EnumType.STRING) private TableState state; private Integer chairs; @Column(name="floor_id") private Long floorId; public Long getId(){return id;} public void setId(Long id){this.id=id;} public Long getOrganizationId(){return organizationId;} public void setOrganizationId(Long organizationId){this.organizationId=organizationId;} public String getName(){return name;} public void setName(String name){this.name=name;} public String getDescription(){return description;} public void setDescription(String description){this.description=description;} public TableState getState(){return state;} public void setState(TableState state){this.state=state;} public Integer getChairs(){return chairs;} public void setChairs(Integer chairs){this.chairs=chairs;} public Long getFloorId(){return floorId;} public void setFloorId(Long floorId){this.floorId=floorId;} }
